// Generate all test files
function ensureDir(dir) {
  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
}

function writeTestFile(examId, testNum, questions) {
  const gradeId = 'grade3';
  const dir = path.join(DATA_DIR, examId, gradeId);
  ensureDir(dir);
  const title = `${examId.toUpperCase()} Grade 3 Test ${testNum}`;
  const data = {
    title,
    durationMinutes: 15,
    questionCount: 10,
    questions: questions.map((q, i) => ({
      id: `${examId}-grade3-test${testNum}-q${i + 1}`,
      questionText: q.q,
      image: "",
      options: q.opts,
      correctAnswer: q.c,
      explanation: q.exp,
      topic: q.topic,
      difficulty: q.diff,
    })),
  };
  const filePath = path.join(dir, `test${testNum}.json`);
  fs.writeFileSync(filePath, JSON.stringify(data, null, 2));
  console.log(`Wrote ${filePath}`);
}

// Write index.json with test metadata for each exam
function writeIndexFile(examId) {
  const gradeId = 'grade3';
  const dir = path.join(DATA_DIR, examId, gradeId);
  const tests = [];
  for (let t = 1; t <= TESTS_PER_EXAM; t++) {
    const fp = path.join(dir, `test${t}.json`);
    if (fs.existsSync(fp)) {
      const d = JSON.parse(fs.readFileSync(fp, 'utf8'));
      tests.push({ id: String(t), title: d.title, durationMinutes: d.durationMinutes ?? 15, questionCount: d.questionCount ?? 10 });
    }
  }
  const indexPath = path.join(dir, 'index.json');
  fs.writeFileSync(indexPath, JSON.stringify({ tests }, null, 2));
  console.log(`Wrote ${indexPath}`);
}

// Interleave questions for topic variety: each test gets questions from different parts of the bank
function pickQuestionsForTest(allQuestions, testNum) {
  const indices = [];
  for (let i = 0; i < QUESTIONS_PER_TEST; i++) {
    indices.push((i * TESTS_PER_EXAM + (testNum - 1)) % 50);
  }
  return indices.map((i) => allQuestions[i]);
}

// Generate all 30 test files (6 exams × 5 tests)
for (const examId of EXAMS) {
  const questions = QUESTION_BANK[examId];
  if (!questions || questions.length < 50) {
    console.warn(`Skipping ${examId}: need 50 questions, got ${questions?.length ?? 0}`);
    continue;
  }
  for (let t = 1; t <= TESTS_PER_EXAM; t++) {
    const testQuestions = pickQuestionsForTest(questions, t);
    writeTestFile(examId, t, testQuestions);
  }
  writeIndexFile(examId);
}
console.log(`Generated ${EXAMS.length * TESTS_PER_EXAM} test files and ${EXAMS.length} index files.`);
